mapper.update:
UPDATE BOARD
   SET CATEGORY_CODE = NULLIF(#{categoryCode}, 0),
       BOARD_TITLE = #{boardTitle},
       BOARD_CONTENT = #{boardContent}
 WHERE BOARD_NO = #{boardNo}
   AND MEMBER_NO = #{memberNo}

UPDATE BOARD
   SET BOARD_ACTIVE = 'N'
 WHERE BOARD_NO = #{boardNo}
   AND MEMBER_NO = #{memberNo}

